import pandas as pd
businesses_with_credit_cards = locals()['var_function-call-8079576247111297975']

category_counts = {}
business_category_map = {}

for business in businesses_with_credit_cards:
    description = business.get('description', '')
    business_id = business.get('business_id')
    if business_id and description:
        # Extract categories from the description string
        # Assuming categories are listed after 'services in ' or 'range of services including ' and separated by commas
        if 'services in ' in description:
            categories_str = description.split('services in ')[1]
        elif 'services including ' in description:
            categories_str = description.split('services including ')[1]
        else:
            categories_str = ''

        categories_list = [cat.strip() for cat in categories_str.replace('.', '').split(',') if cat.strip()]

        for category in categories_list:
            category_counts[category] = category_counts.get(category, 0) + 1
            if category not in business_category_map:
                business_category_map[category] = []
            business_category_map[category].append(business_id)

# Find the category with the largest number of businesses
most_common_category = max(category_counts, key=category_counts.get)

# Get business_ids for the most common category
business_ids_for_most_common_category = business_category_map.get(most_common_category, [])

# Prepare data for next steps
result = {
    'most_common_category': most_common_category,
    'business_ids_for_most_common_category': business_ids_for_most_common_category
}
print('__RESULT__:')
print(pd.json_normalize(result).to_json(orient='records'))

